class Graph:
    def __init__(self):
        self.vertices = {}
    def add_edge(self, u, v):
        self.vertices.setdefault(u, []).append(v)
        self.vertices.setdefault(v, []).append(u)
    def bfs(self, start):
        visited = set()
        queue = [start]
        while queue:
            v = queue.pop(0)
            if v not in visited:
                visited.add(v)
                queue.extend(n for n in self.vertices[v] if n not in visited)
        return visited

